content:
                    centroid,
                });
            }
        }

        ClusterHierarchy {
            super_clusters,
            sub_clusters,
            entry_count: entries.len(),
            computed_at: chrono::Utc::now(),
        }
    }
pub fn cluster_for_entry(&self, entry_id: &str) -> Option<&ClusterNode> {
        self.super_clusters
            .iter()
            .find(|sc| sc.entry_ids.contains(&entry_id.to_string()))
    }
